API versioning strategies: URI path versioning (/v1/, /v2/), query parameters, custom headers, content negotiation. Each has trade-offs.

**Common strategies:**

```java
// Strategy 1: URI Path Versioning (most common)
@RestController
@RequestMapping("/api/v1/orders")
public class OrderControllerV1 {

    @PostMapping
    public ResponseEntity<OrderResponseV1> create(@RequestBody OrderRequestV1 req) {
        // V1 response format
        return ResponseEntity.ok(new OrderResponseV1(/* ... */));
    }
}

@RestController
@RequestMapping("/api/v2/orders")
public class OrderControllerV2 {

    @PostMapping
    public ResponseEntity<OrderResponseV2> create(@RequestBody OrderRequestV2 req) {
        // V2 has new fields: discountCode, loyaltyPoints
        return ResponseEntity.ok(new OrderResponseV2(/* ... */));
    }
}

// Pros: Explicit, easy to maintain, backwards compatible
// Cons: Duplicate code, multiple endpoints

// Strategy 2: Request Header Versioning
@RestController
@RequestMapping("/api/orders")
public class OrderController {

    @PostMapping
    public ResponseEntity<?> create(
        @RequestBody OrderRequest req,
        @RequestHeader(value = "X-API-Version", defaultValue = "1") int version) {

        if (version == 1) {
            return ResponseEntity.ok(createV1Response(req));
        } else if (version == 2) {
            return ResponseEntity.ok(createV2Response(req));
        }
    }
}

// Usage: curl -H "X-API-Version: 2" http://api.com/orders
// Pros: Single endpoint, cleaner URLs
// Cons: Version hidden in headers, harder to debug

// Strategy 3: Accept Header / Content Negotiation
@RestController
public class OrderController {

    @PostMapping(value = "/orders", 
                 consumes = "application/vnd.company.v1+json")
    public ResponseEntity<OrderResponseV1> createV1(@RequestBody OrderRequestV1 req) {
