        return ResponseEntity.ok(new OrderResponseV1(req));
    }

    @PostMapping(value = "/orders",
                 consumes = "application/vnd.company.v2+json")
    public ResponseEntity<OrderResponseV2> createV2(@RequestBody OrderRequestV2 req) {
        // V2: consumes application/vnd.company.v2+json
        return ResponseEntity.ok(new OrderResponseV2(req));
    }
}

// Usage: 
// curl -H "Content-Type: application/vnd.company.v1+json" -d @order.json http://api.com/orders
// curl -H "Content-Type: application/vnd.company.v2+json" -d @order.json http://api.com/orders

